// ===========================================================
// NODO 1: CODE ROUTER
// Selecciona el agente correcto según bucket y fase.
// Construye el prompt para Gemini.
// ===========================================================

// Soporta tanto body anidado (n8n webhook default) como payload directo
const datos = $input.first().json.body || $input.first().json;

const bucket          = datos.bucket          || '1-7';
const fase            = datos.fase            || 'apertura';
const nombre          = datos.nombre_cliente  || 'cliente';
const pagos           = datos.pagos_vencidos  || 1;
const monto           = datos.monto_pago      || 0;
const saldo_vencido   = datos.saldo_vencido   || 0;
const ultima_gestion  = datos.ultima_gestion  || 'Sin gestión previa';
const telefono        = datos.telefono        || '';

// ── Prompts de sistema por tipo de agente ────────────
const PROMPTS_SISTEMA = {

  empatico:
    `Eres un agente de cobranza empático y profesional de Libertad Financiera.\n     Tu objetivo es recuperar el pago sin agredir al cliente.\n     Usa lenguaje claro, humano y orientado a solución.\n     Invita a regularizar hoy de forma amable.\n     No uses amenazas ni lenguaje agresivo.\n     Responde ÚNICAMENTE con el mensaje de WhatsApp, sin comillas, sin explicaciones.`,

  firme:
    `Eres un agente de cobranza firme, directo y profesional de Libertad Financiera.\n     Tu objetivo es obtener pago o compromiso concreto hoy.\n     Sé claro con el atraso, el monto y la urgencia de regularizar.\n     Tono serio y respetuoso. Sin insultos ni amenazas ilegales.\n     Responde ÚNICAMENTE con el mensaje de WhatsApp, sin comillas, sin explicaciones.`,

  conciliador:
    `Eres un agente conciliador de cobranza de Libertad Financiera.\n     Busca una salida viable: pago total, pago parcial o fecha exacta de depósito.\n     Tono profesional, orientado a negociación y acuerdo.\n     Responde ÚNICAMENTE con el mensaje de WhatsApp, sin comillas, sin explicaciones.`,

  cierre:
    `Eres un agente de cierre de cobranza de Libertad Financiera.\n     Acción concreta: pago hoy, transferencia o fecha y hora exacta.\n     Máximo 4 líneas. Sin saludos largos. Sin rodeos.\n     Responde ÚNICAMENTE con el mensaje de WhatsApp, sin comillas, sin explicaciones.`
};

// ── Selección de agente ───────────────────────────
// Regla 1: Si fase es 'cierre' → siempre Agente Cierre
// Regla 2: Bucket 61-90 / 91-120 → Conciliador
// Regla 3: Bucket 31-60 → Firme
// Default: Empático (0, 1-7, 8-15, 16-30)
let agente = 'empatico';
if (fase === 'cierre') {
  agente = 'cierre';
} else if (['61-90', '91-120'].includes(bucket)) {
  agente = 'conciliador';
} else if (bucket === '31-60') {
  agente = 'firme';
}

// ── Contexto de la cuenta ─────────────────────────
const contexto_cuenta =
  `Genera un mensaje de WhatsApp de cobranza para ${nombre}.\n` +
  `Situación: ${pagos} pago(s) vencido(s) | Monto de pago: $${monto} MXN | ` +
  `Saldo vencido: $${saldo_vencido} MXN | Bucket: ${bucket} días | Fase: ${fase}.\n` +
  `Última gestión registrada: "${ultima_gestion}".\n` +
  `El mensaje debe estar en español mexicano, ser profesional, máximo 5 líneas, ` +
  `y solicitar una acción concreta hoy (pago, transferencia o fecha exacta).`;

// ── Output ───────────────────────────────────────
return [{
  json: {
    ...datos,
    agente_seleccionado: agente,
    gemini_body: {
      contents: [{
        parts: [{
          text: PROMPTS_SISTEMA[agente] + '\n\n' + contexto_cuenta
        }]
      }],
      generationConfig: {
        temperature: 0.7,
        maxOutputTokens: 300
      }
    }
  }
}];

// ===========================================================
// NODO 2: CODE NORMALIZER
// Extrae el texto de Gemini y recupera datos del Code Router.
// ===========================================================

const gemini   = $input.first().json;
const original = $('Code Router').first().json;

let mensaje_ia = '';
try {
  mensaje_ia =
    gemini.candidates?.[0]?.content?.parts?.[0]?.text ||
    gemini.text ||
    gemini.response ||
    gemini.output_text ||
    JSON.stringify(gemini);
} catch (e) {
  mensaje_ia = 'Error al procesar respuesta de IA: ' + e.message;
}

mensaje_ia = mensaje_ia.trim();

// Limpiar comillas envolventes que Gemini a veces añade
if (mensaje_ia.startsWith('"') && mensaje_ia.endsWith('"')) {
  mensaje_ia = mensaje_ia.slice(1, -1).trim();
}

// Formato internacional de teléfono (+52 México)
let telefono = String(original.telefono || '').replace(/\D/g, '');
if (!telefono.startsWith('52') && telefono.length === 10) {
  telefono = '52' + telefono;
}

return [{
  json: {
    status: 'ok',
    mensaje_ia,
    telefono,
    agente_seleccionado: original.agente_seleccionado,
    cliente_id:          original.cliente_id      || null,
    nombre_cliente:      original.nombre_cliente  || 'cliente',
    bucket:              original.bucket          || null,
    fase:                original.fase            || null,
    origen: 'gemini-espartanos'
  }
}];

